import React from "react"
import User from "./User"

class Users extends React.Component {
    render() {
        return (
            <div>
                {this.props.users.map((item) => (
                    <User key={item.id} user={item} onDelete={this.props.onDelete}/>
                ))}
            </div>
        )
    }
}



export default Users
